@namespace sv_66cbea548d0741718173d013011549e6.Components.Pages.Apply
@using sv_66cbea548d0741718173d013011549e6.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <text>Validating…</text>
        }
        else
        {
            <text>Next →</text>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService AppService { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? errorMessage;
    private bool isValidating;

    private async Task HandleNext()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) || string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) || string.IsNullOrWhiteSpace(Model.Address))
        {
            errorMessage = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var isValidEmail = await AppService.ValidateEmailAsync(Model.Email);
            if (!isValidEmail)
            {
                errorMessage = "The email address is not valid. Please check and try again.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@namespace sv_66cbea548d0741718173d013011549e6.Components.Pages.Apply
@using sv_66cbea548d0741718173d013011549e6.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]" Index="index" CanRemove="Entries.Count > 1" OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary btn-sm mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                errorMessage = "Each position must have a company name and job title.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_66cbea548d0741718173d013011549e6.Components.Pages.Apply
@using sv_66cbea548d0741718173d013011549e6.Models

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]" Index="index" CanRemove="References.Count > 2" OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary btn-sm mb-4" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_66cbea548d0741718173d013011549e6.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput"
              maxlength="@MaxLength"
              placeholder="Tell us why you're a great fit for this role…"></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
    <button class="btn btn-primary" @onclick="() => OnNext.InvokeAsync()">Next →</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}

@namespace sv_66cbea548d0741718173d013011549e6.Components.Pages.Apply
@using sv_66cbea548d0741718173d013011549e6.Models

<h4 class="mb-3">Review & Submit</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<!-- Personal Info -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEdit.InvokeAsync(0)'>Edit</button>
    </div>
    <div class="card-body">
        <div class="row">
            <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
            <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
            <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
            <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
        </div>
    </div>
</div>

<!-- Work History -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEdit.InvokeAsync(1)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom">
                <div><strong>@entry.Title</strong> at @entry.Company</div>
                <div class="text-muted small">
                    @entry.StartDate.ToString("MMM yyyy") – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </div>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <div class="mt-1">@entry.Description</div>
                }
            </div>
        }
    </div>
</div>

<!-- References -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEdit.InvokeAsync(2)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
            </div>
        }
    </div>
</div>

<!-- Cover Letter -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEdit.InvokeAsync(3)'>Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
    <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
        @if (isSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <text>Submitting…</text>
        }
        else
        {
            <text>Submit Application</text>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnSubmitted { get; set; }
    [Parameter, EditorRequired] public IApplicationService AppService { get; set; } = default!;

    private bool isSubmitting;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            var applicationId = await AppService.SubmitApplicationAsync(application);
            await OnSubmitted.InvokeAsync(applicationId);
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

