    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService AppService { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? errorMessage;
    private bool isValidating;

    private async Task HandleNext()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) || string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) || string.IsNullOrWhiteSpace(Model.Address))
        {
            errorMessage = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var isValidEmail = await AppService.ValidateEmailAsync(Model.Email);
            if (!isValidEmail)
            {
                errorMessage = "The email address is not valid. Please check and try again.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

