@namespace sv_66cbea548d0741718173d013011549e6.Components.Pages.Apply
@using sv_66cbea548d0741718173d013011549e6.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]" Index="index" CanRemove="Entries.Count > 1" OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary btn-sm mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                errorMessage = "Each position must have a company name and job title.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

