@page "/apply"
@rendermode InteractiveServer
@namespace sv_66cbea548d0741718173d013011549e6.Components.Pages.Apply
@using sv_66cbea548d0741718173d013011549e6.Models
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (submittedId.HasValue)
    {
        <div class="alert alert-success text-center py-5">
            <h3 class="mb-3">🎉 Application Submitted!</h3>
            <p class="lead">Your application has been received.</p>
            <p><strong>Application ID: @submittedId.Value</strong></p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo" AppService="AppService" OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 2:
                <ReferencesStep References="references" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetter="coverLetter" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 4:
                <ReviewStep Personal="personalInfo" WorkEntries="workEntries" References="references"
                            CoverLetter="coverLetter" AppService="AppService"
                            OnEdit="GoToStep" OnBack="PrevStep" OnSubmitted="HandleSubmitted" />
                break;
        }
    }
</div>

@code {
    private int currentStep;
    private readonly HashSet<int> completedSteps = new();
    private int? submittedId;

    // Shared form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PrevStep()
    {
        currentStep--;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void HandleSubmitted(int applicationId)
    {
        submittedId = applicationId;
    }
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    font-size: 0.85rem;
    font-weight: 600;
}

.step-item.completed .step-circle {
    font-size: 1rem;
}

/* Connector line between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 1rem;
    left: calc(50% + 1.2rem);
    width: calc(100% - 2.4rem);
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

